Rule.Source:
  import sailpoint.object.Custom;
  import sailpoint.object.Identity;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.Attributes;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.Operation;  
  import sailpoint.object.ProvisioningPlan.AccountRequest; 
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.WorkflowLaunch;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;	
  import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.Application;
  import sailpoint.object.ResourceObject;
  import sailpoint.connector.Connector;
  import sailpoint.connector.ADLDAPConnector;
  import sailpoint.api.Provisioner;
  import sailpoint.api.Workflower;
  import java.io.File;
  import java.io.IOException;
  import sailpoint.object.EmailFileAttachment;
  import java.io.FileInputStream;
  
  //import sailpoint.connector.ConnectorClassLoader;

//ClassLoader currentCl = Thread.currentThread().getContextClassLoader();
//ClassLoader bakcedUpCl = null;
//if(currentCl instanceof ConnectorClassLoader){
//bakcedUpCl = currentCl;
//Thread.currentThread().setContextClassLoader(currentCl.getParent());
//}

  /**
		 * 
		 * @Send Email if operation is create AD Account for Contractors    
		 */



  Log logger = LogFactory.getLog("rule.afterProvisioning.AD");
  logger.debug("Entering AD After Provisioning Rule");
  String toEmail = null;
  Identity owner = null;
  String result = null;
  String displayName = null;
  String ministryName = null;
  String ccEmail = null;
  String distributionList = null;
  String status = null;
  String userType = null;
  String ctrMgr = null;
  String ctrMgrEmail= null;
  List userTypes = new ArrayList();
  HashMap distributionLists = new HashMap();
  LinkedHashMap argValues = new LinkedHashMap();
  String additionalDomain = "";
  String selectorRuleSource = "";
  String operationName = "";

  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
  if(custom !=null && custom.get("userTypes") !=null){
    userTypes = custom.get("userTypes");
    if(null != custom.get("DistributionList")){
      distributionLists = custom.get("DistributionList");	
    }
    //comment decache //context.decache(custom);
  }
  if (plan != null ) { 
    if(null != plan.getIdentity()){
      displayName = plan.getIdentity().getDisplayName();
      ministryName = plan.getIdentity().getAttribute("ministry");
      userType = plan.getIdentity().getAttribute("type"); 
      ctrMgr = plan.getIdentity().getAttribute("contractorManager");	  
    }		
    if(null != userTypes && userTypes.contains(userType)){  
      List accountRequests = plan.getAccountRequests(application.getName());
      if(null != accountRequests && !accountRequests.isEmpty()){
        for(AccountRequest accountRequest : accountRequests){
          if(accountRequest != null && accountRequest.getResult() != null){ 
            status = accountRequest.getResult().getStatus();  
            if(Util.isNotNullOrEmpty(status) && status.equalsIgnoreCase("COMMITTED")){
              AttributeRequest attrReq = accountRequest.getAttributeRequest("sAMAccountName");     
              AttributeRequest passwordAD = accountRequest.getAttributeRequest("password");              
              if(null != accountRequest.getOperation() && (AccountRequest.Operation.Create.equals(accountRequest.getOperation()) || AccountRequest.Operation.Enable.equals(accountRequest.getOperation()))){
                if(null != plan.getIdentity()){
                  Attributes atts  = new Attributes();
                  if(accountRequest.getArguments()!=null){
                    atts = accountRequest.getArguments();
                    operationName = atts.get("operationName");
                    additionalDomain = atts.get("additionalDomain");
                    selectorRuleSource = atts.get("selectorRuleSource");
                  }
                  if(Util.isNotNullOrEmpty(operationName) && operationName.equalsIgnoreCase("Rehire")){
                    continue;
                  }
                  if(Util.isNotNullOrEmpty(additionalDomain) && Util.isNotNullOrEmpty(selectorRuleSource)){
                    List requesters = plan.getRequesters();
                    String requesterName; 
                    if(!Util.isEmpty(requesters)){
                      for(Identity requester : requesters){
                        if(null != requester && !requester.isInactive()){
                          toEmail = requester.getAttribute("email");
                          requesterName =  requester.getFirstname();
                          break;
                        }	
                      }
                    }
                    if (null != attrReq){                                    
                      argValues.put("Username",additionalDomain+"\\"+attrReq.getValue());
                    }
                    if (null != passwordAD){                                    
                      argValues.put("Password",passwordAD.getValue());
                    }
                    if(null != plan.getArguments()){
                      argValues.put("Request Number",plan.getArguments().get("identityRequestId"));
                    }
                    argValues.put("Requestee Name",plan.getIdentity().getDisplayName());
                    argValues.put("Requestee Identity",plan.getIdentity().getName());
                    argValues.put("additionalAccount","additionalAccount");
                    argValues.put("requesterFirstName",requesterName);
                    if(null != distributionLists){
                      ccEmail = distributionLists.get(plan.getIdentity().getAttribute("additionalDomain"));                  
                    }
                  }
                  else{
                    owner = plan.getIdentity().getManager();
                    if(null != owner && !owner.isInactive()){
                      toEmail = owner.getAttribute("email");
                    }	
                    if (null != attrReq){                
                      argValues.put("NetworkID",attrReq.getValue());                    
                    }
                    else{
                      argValues.put("NetworkID",plan.getIdentity().getAttribute("samAccountName"));
                    }
                    if (null != passwordAD){                                    
                      argValues.put("Temporary Password",passwordAD.getValue());
                    }
                    argValues.put("Name",plan.getIdentity().getDisplayName());                      
                    argValues.put("Health Ministry",ministryName);
                    argValues.put("Worker Type",userType);
                    argValues.put("Start Date",plan.getIdentity().getAttribute("hireDate"));
                    argValues.put("End Date",plan.getIdentity().getAttribute("ctrexpDt"));  
                    if(null != owner){
                      argValues.put("Hiring Manager",owner.getDisplayName());
                    }

                    argValues.put("G Suite Account",plan.getIdentity().getAttribute("email"));
                    argValues.put("Domain",plan.getIdentity().getAttribute("domain"));
                    argValues.put("Worker ID",plan.getIdentity().getAttribute("employeeId"));
                    argValues.put("Business Unit",plan.getIdentity().getAttribute("businessUnit"));
                    argValues.put("Corporate Job Code",plan.getIdentity().getAttribute("jobcode"));
                    if(null != distributionLists){
                      ccEmail = distributionLists.get(plan.getIdentity().getAttribute("domain"));                  
                    }
                  }
                  if(Util.isNotNullOrEmpty(ctrMgr)){
                    Identity ctrMgrID = context.getObjectByName(Identity.class,ctrMgr);
                    if(null != ctrMgrID && !ctrMgrID.isInactive()){
                      ctrMgrEmail = ctrMgrID.getAttribute("email");
                    }	
                    if(null != ctrMgrID ){
                      //context.decache(ctrMgrID );
                    }				
                  }
                }

                String updatedCCEmail = "";
                String pdfFilePath = null;
                String fileName = null;  
                byte[] fileBytes= null;
                FileInputStream fis = null;
                EmailFileAttachment attachment = null;

                if(custom !=null && custom.get("consentForm") !=null){
                  fileName = custom.get("consentForm").get("fileName").toString();
                  pdfFilePath = custom.get("consentForm").get("pdfFilePath").toString();
                }
                EmailTemplate template = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-ManagerNotification");
                EmailOptions options = new EmailOptions();
                if(Util.isNotNullOrEmpty(toEmail)){
                  options.setTo(toEmail);
                }

                if(null !=cc){
                  updatedCCEmail = ccEmail + "," + ctrMgrEmail;
                  options.setCc(updatedCCEmail);
                }

                Map args = new HashMap();
                args.put("Map",argValues);
                args.put("identityDisplayName",displayName);
                if(AccountRequest.Operation.Create.equals(accountRequest.getOperation())){
                  args.put("operation","Creation");
                }else if (AccountRequest.Operation.Enable.equals(accountRequest.getOperation())){
                  args.put("operation","Rehire");   
                }
                options.setVariables(args);
                File file = new File(pdfFilePath);
                if(file.exists()){
                  fileBytes = new byte[(int) file.length()];
                  fis = new FileInputStream(file);
                  fis.read(fileBytes);   
                  attachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_PDF, fileBytes);
                  options.addAttachment( attachment );
                }else{
                  logger.error("File does not exist in the specified location: "+pdfFilePath+" ,Need Consent form file to be present in the location for the email attachment to be sent");        
                } 
                if(Util.isNotNullOrEmpty(toEmail) && template !=null){

                  context.sendEmailNotification(template,options);
                  //comment decache //context.decache(template);
                  
                }
              }        
            }
          }
          //additional network code to remove role
          String workflowName = "Ascension-Workflow-Remove-Additional-AD-Role";
          Attributes atts  = new Attributes();
          if(accountRequest.getArguments()!=null){
            atts = accountRequest.getArguments();
            String additionalDomain = atts.get("additionalDomain");
            String selectorRuleSource = atts.get("selectorRuleSource");


            if(Util.isNotNullOrEmpty(additionalDomain) && Util.isNotNullOrEmpty(selectorRuleSource) ){
              if(null != plan.getIdentity()){
                logger.debug(workflowName +" Workflow Starting");
                WorkflowLaunch wfl = new WorkflowLaunch();
                wfl.setWorkflowRef(workflowName);
                wfl.setLauncher(context.getUserName());
                wfl.setCaseName(workflowName +" - "+ plan.getIdentity().getName());
                Map wfArgsMap =  new HashMap();
                wfArgsMap.put("identityName", plan.getIdentity().getName());
                wfArgsMap.put("roleName", selectorRuleSource);
                wfl.setVariables(wfArgsMap);
                Workflower wf = new Workflower(context);
                try {
                  wf.launch(wfl);
                  logger.debug(workflowName+" launch successfully");

                } catch (GeneralException e) {
                  logger.error("Exception in launching Ascension-Workflow-Remove-Additional-AD-Role  " + e.getMessage());
                }
              }
            }
          }
          //additional network code to remove role

          AttributeRequest ar = accountRequest.getAttributeRequest("AC_NewParent");
          if (null == ar) {
            ar = accountRequest.getAttributeRequest("AC_NewName");
          }
          if (null == ar) {
            logger.debug("Not a rename or move. There might be a connector error in account request . Bypassing AfterProvisioning logic.");  
            break; 
          }
          // If there was failure in connector, bypass everything.
          ProvisioningResult result = accountRequest.getResult();
          if (result!=null && !result.getStatus().equals(ProvisioningResult.STATUS_FAILED)) {
            if (ar.getName().equals("AC_NewParent")) {
              logger.debug("AC_NewParent AttributeRequest");
              String oldDN = accountRequest.getNativeIdentity();
              // Pull the new OU from the AttributeRequest and build a new DN
              String newOU = (String) ar.getValue();
              int indexOfDomain = 0;
              String cn = "";
              if(oldDN.contains("\\")){
                indexOfDomain = oldDN.toLowerCase().indexOf(",", oldDN.indexOf(",") + 1);
              }else{
                indexOfDomain = oldDN.toLowerCase().indexOf(",", oldDN.indexOf(","));
              }
              //this index should be the start of the parent
              if(indexOfDomain > 0){
                cn = oldDN.substring(0,indexOfDomain);
              }
              String newDN = cn + "," + newOU;
              // Let's call the connector to get the newly moved object
              Application app = context.getObjectByName(Application.class,application.getName());
              sailpoint.connector.Connector conn = sailpoint.connector.ConnectorFactory.getConnector(app, null); 
              Map map = new HashMap();
              int c=0;
              ResourceObject ro=null;
              while(c<100){ 
                try {
                  ro = conn.getObject("account",newDN,map);
                }catch (sailpoint.connector.ObjectNotFoundException onfe) {  
                  logger.debug("Object not found Attempt #"+c);
                } 
                if(ro!=null)
                  break;
                Thread.sleep(100); 
                c=c+1;
              }
              if(ro!=null){
                // Stuff the resource object in the place where the Provisioner will find it
                ProvisioningResult result = accountRequest.getResult();
                result.setObject(ro);
                accountRequest.setResult(result);
                // Scramble the native identity to force a link creation
                accountRequest.setNativeIdentity("#DOES_NOT_EXIST#");
                // Need to clean out the old link...
                AccountRequest delete = new AccountRequest();
                delete.setApplication(application.getName());
                delete.setNativeIdentity(oldDN);
                delete.setOperation(Operation.Delete);
                ProvisioningResult pr = new ProvisioningResult();
                pr.setStatus(ProvisioningResult.STATUS_COMMITTED);
                delete.setResult(pr);
                plan.add(delete);
              }
            }
          }
        }
      }
    }
  }

  logger.debug("Exiting AD Provisioning Rule");
